mapper.select:
SELECT POINT_ID as id, POINT_NAME, LONGITUDE, LATITUDE, TYPE, STATUS, CREATE_TIME, CREATE_BY, UPDATE_BY, UPDATE_TIME FROM t_keypoints
1=1
and POINT_ID=#{id}
and STATUS=#{status}

SELECT T1.ROUTE_ID, T1.ROUTE_NAME, T1.BEGIN_PID, T1.END_PID, T1.ROUTE_TYPE, T1.STATUS, T1.CREATE_BY, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_TIME, T2.LONGITUDE AS START_LON, T2.LATITUDE AS START_LAT, T3.LONGITUDE AS END_LON, T3.LATITUDE AS END_LAT FROM T_ROUTES T1 INNER JOIN T_KEYPOINTS T2 ON T1.BEGIN_PID = T2.POINT_ID INNER JOIN T_KEYPOINTS T3 ON T1.END_PID = T3.POINT_ID
1=1
and ROUTE_ID=#{routeId}
